import{_ as e,c as o,o as a,ag as s}from"./chunks/framework.B58IbkZx.js";const r="data:image/png;base64,",i="/1.0.0-PRO/assets/conditions-dropdown.C0SE6f8q.png",n="/1.0.0-PRO/assets/conditions-user-role.C0gynqxw.png",l="/1.0.0-PRO/assets/conditions-with-without.BqOz5GI4.png",d="/1.0.0-PRO/assets/conditions-role-select.BXEncd8M.png",c="/1.0.0-PRO/assets/conditions-user-roles.Bdtkyjq7.png",h="/1.0.0-PRO/assets/conditions-user-roles-with-without.BhgTnFlQ.png",u="/1.0.0-PRO/assets/conditions-user-roles-selected.Bue94wwV.png",p="/1.0.0-PRO/assets/conditions-users.Df6vi5-p.png",g="/1.0.0-PRO/assets/conditions-users-include-exclude.Dz5b2We9.png",q=JSON.parse('{"title":"Conditions","description":"","frontmatter":{},"headers":[],"relativePath":"core-concepts/conditions.md","filePath":"core-concepts/conditions.md","lastUpdated":1769871666000}'),m={name:"core-concepts/conditions.md"};function b(f,t,y,C,w,P){return a(),o("div",null,t[0]||(t[0]=[s('<h1 id="conditions" tabindex="-1">Conditions <a class="header-anchor" href="#conditions" aria-label="Permalink to &quot;Conditions&quot;">​</a></h1><p>Campaign Bay allows you to add <strong>Conditions</strong> to any campaign. These conditions &quot;gate&quot; the discount, ensuring it only applies when specific criteria are met.</p><hr><h2 id="how-conditions-work" tabindex="-1">How Conditions Work <a class="header-anchor" href="#how-conditions-work" aria-label="Permalink to &quot;How Conditions Work&quot;">​</a></h2><p>Every campaign includes a <strong>Conditions</strong> section where you can add one or more rules.</p><h3 id="match-logic" tabindex="-1">Match Logic <a class="header-anchor" href="#match-logic" aria-label="Permalink to &quot;Match Logic&quot;">​</a></h3><p><img src="'+r+'" alt="Match Any / Match All Toggle"></p><table tabindex="0"><thead><tr><th>Mode</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Match Any</strong></td><td>Discount applies if <em>at least one</em> condition is true</td></tr><tr><td><strong>Match All</strong></td><td>Discount applies <em>only if all</em> conditions are true</td></tr></tbody></table><h3 id="adding-conditions" tabindex="-1">Adding Conditions <a class="header-anchor" href="#adding-conditions" aria-label="Permalink to &quot;Adding Conditions&quot;">​</a></h3><p>Click <strong>Add New Condition</strong> to see the available options:</p><p><img src="'+i+'" alt="Conditions Dropdown"></p><hr><h2 id="available-conditions" tabindex="-1">Available Conditions <a class="header-anchor" href="#available-conditions" aria-label="Permalink to &quot;Available Conditions&quot;">​</a></h2><h3 id="_1-user-role-single" tabindex="-1">1. User Role (Single) <a class="header-anchor" href="#_1-user-role-single" aria-label="Permalink to &quot;1. User Role (Single)&quot;">​</a></h3><p>Restrict the campaign to users with a <strong>single specific</strong> WordPress role.</p><p><img src="'+n+'" alt="User Role Condition"></p><h4 id="with-without-toggle" tabindex="-1">With / Without Toggle <a class="header-anchor" href="#with-without-toggle" aria-label="Permalink to &quot;With / Without Toggle&quot;">​</a></h4><p><img src="'+l+'" alt="With Without Dropdown"></p><table tabindex="0"><thead><tr><th>Option</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>with</strong></td><td>Only users <em>with</em> the selected role can use this discount</td></tr><tr><td><strong>without</strong></td><td>Users <em>without</em> the selected role can use this discount</td></tr></tbody></table><h4 id="select-user-role" tabindex="-1">Select User Role <a class="header-anchor" href="#select-user-role" aria-label="Permalink to &quot;Select User Role&quot;">​</a></h4><p><img src="'+d+'" alt="Role Selection Dropdown"></p><p>Choose from any WordPress role on your site:</p><ul><li>Administrator, Editor, Author, Contributor, Subscriber</li><li>WooCommerce roles: Customer, Shop Manager</li><li>Custom roles from other plugins</li></ul><div class="tip custom-block"><p class="custom-block-title">Use Case</p><p>Create a &quot;VIP Only&quot; sale: <code>User Role</code> → <code>with</code> → <code>VIP Customer</code></p></div><hr><h3 id="_2-user-roles-multiple" tabindex="-1">2. User Roles (Multiple) <a class="header-anchor" href="#_2-user-roles-multiple" aria-label="Permalink to &quot;2. User Roles (Multiple)&quot;">​</a></h3><p>Restrict the campaign to users with <strong>one of several</strong> WordPress roles.</p><p><img src="'+c+'" alt="User Roles Condition"></p><h4 id="with-without-toggle-1" tabindex="-1">With / Without Toggle <a class="header-anchor" href="#with-without-toggle-1" aria-label="Permalink to &quot;With / Without Toggle&quot;">​</a></h4><p><img src="'+h+'" alt="User Roles With Without"></p><table tabindex="0"><thead><tr><th>Option</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>with</strong></td><td>Only users with <em>any</em> of the selected roles can use this discount</td></tr><tr><td><strong>without</strong></td><td>Users <em>without any</em> of the selected roles can use this discount</td></tr></tbody></table><h4 id="multi-select-roles" tabindex="-1">Multi-Select Roles <a class="header-anchor" href="#multi-select-roles" aria-label="Permalink to &quot;Multi-Select Roles&quot;">​</a></h4><p><img src="'+u+'" alt="User Roles Selected"></p><p>Select multiple roles — user must have <strong>at least one</strong> of the selected roles.</p><div class="tip custom-block"><p class="custom-block-title">Use Case</p><p>Create a wholesale discount: <code>User Roles</code> → <code>with</code> → <code>Wholesale Buyer, VIP Customer</code></p></div><hr><h3 id="_3-users-specific" tabindex="-1">3. Users (Specific) <a class="header-anchor" href="#_3-users-specific" aria-label="Permalink to &quot;3. Users (Specific)&quot;">​</a></h3><p>Restrict the campaign to <strong>specific individual users</strong> by name or email.</p><p><img src="'+p+'" alt="Users Condition"></p><h4 id="include-exclude-toggle" tabindex="-1">Include / Exclude Toggle <a class="header-anchor" href="#include-exclude-toggle" aria-label="Permalink to &quot;Include / Exclude Toggle&quot;">​</a></h4><p><img src="'+g+'" alt="Users Include Exclude"></p><table tabindex="0"><thead><tr><th>Option</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Include</strong></td><td>Only the selected users can use this discount</td></tr><tr><td><strong>Exclude</strong></td><td>Everyone <em>except</em> the selected users can use this discount</td></tr></tbody></table><h4 id="multi-select-users" tabindex="-1">Multi-Select Users <a class="header-anchor" href="#multi-select-users" aria-label="Permalink to &quot;Multi-Select Users&quot;">​</a></h4><p>Select multiple users from the dropdown — search by name or email.</p><div class="tip custom-block"><p class="custom-block-title">Use Case</p><p>Create a personal thank-you discount for top customers: <code>Users</code> → <code>Include</code> → <code>john@example.com, jane@example.com</code></p></div><hr><h2 id="pro-conditions" tabindex="-1">Pro Conditions <a class="header-anchor" href="#pro-conditions" aria-label="Permalink to &quot;Pro Conditions&quot;">​</a></h2><p><a href="https://wpanchorbay.com/campaignbay" target="_blank" rel="noreferrer"><strong>CampaignBayPro</strong></a> unlocks additional powerful conditions:</p><h3 id="order-history-count" tabindex="-1">Order History Count <a class="header-anchor" href="#order-history-count" aria-label="Permalink to &quot;Order History Count&quot;">​</a></h3><p>Reward loyal customers based on their previous order count.</p><table tabindex="0"><thead><tr><th>Operator</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>greater than</strong></td><td>Customer must have more than X previous orders</td></tr><tr><td><strong>less than</strong></td><td>Customer must have fewer than X previous orders</td></tr><tr><td><strong>equal to</strong></td><td>Customer must have exactly X previous orders</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Use Case</p><p>Create a loyalty reward: <code>Order History Count</code> → <code>greater than</code> → <code>5</code> to reward customers with 6+ orders.</p></div><h3 id="cart-total-subtotal" tabindex="-1">Cart Total / Subtotal <a class="header-anchor" href="#cart-total-subtotal" aria-label="Permalink to &quot;Cart Total / Subtotal&quot;">​</a></h3><p>Trigger discounts when the cart reaches a certain value.</p><table tabindex="0"><thead><tr><th>Operator</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>greater than</strong></td><td>Cart total must exceed X amount</td></tr><tr><td><strong>less than</strong></td><td>Cart total must be below X amount</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Use Case</p><p>Free shipping incentive: <code>Cart Total</code> → <code>greater than</code> → <code>$100</code> to encourage larger purchases.</p></div><h3 id="specific-product-in-cart" tabindex="-1">Specific Product in Cart <a class="header-anchor" href="#specific-product-in-cart" aria-label="Permalink to &quot;Specific Product in Cart&quot;">​</a></h3><p>Activate a campaign only when a designated &quot;trigger&quot; product is present.</p><div class="tip custom-block"><p class="custom-block-title">Use Case</p><p>Cross-sell: When customer adds a Camera to cart, offer 20% off Camera Bags.</p></div><h3 id="specific-category-in-cart" tabindex="-1">Specific Category in Cart <a class="header-anchor" href="#specific-category-in-cart" aria-label="Permalink to &quot;Specific Category in Cart&quot;">​</a></h3><p>Apply discounts when a product from a specific category is in the cart.</p><div class="tip custom-block"><p class="custom-block-title">Use Case</p><p>Bundle deal: When customer has any item from &quot;Electronics,&quot; offer 15% off &quot;Accessories.&quot;</p></div><p><a href="https://wpanchorbay.com/campaignbay" target="_blank" rel="noreferrer"><strong>Upgrade to CampaignBayPro →</strong></a></p><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Now that you know how to apply specific rules to users and roles, learn how to target your discounts to specific products and categories.</p><ul><li><strong><a href="./targeting.html">Targeting →</a></strong></li></ul><p>Need more advanced conditions? <strong><a href="https://wpanchorbay.com/campaignbay" target="_blank" rel="noreferrer">Get CampaignBayPro →</a></strong></p>',68)]))}const v=e(m,[["render",b]]);export{q as __pageData,v as default};
